'use client'
import { useCart, totals } from '@/store/cart'
import { TrashIcon } from '@heroicons/react/24/outline'
import { CheckoutModal } from './CheckoutModal'

export function CartSidebar() {
  const items = useCart(s => s.items)
  const remove = useCart(s => s.remove)
  const setQty = useCart(s => s.setQty)
  const discount = useCart(s => s.discount)
  const setDiscount = useCart(s => s.setDiscount)
  const { subtotal, tax, total } = totals(items, discount)

  return (
    <div className="w-96 neumorphic p-6 space-y-6">
      <div className="text-lg font-semibold text-primary">Cart</div>
      <div className="space-y-4 max-h-[50vh] overflow-auto">
        {items.map(i => (
          <div key={i.id} className="neumorphic-flat p-4 flex items-center justify-between">
            <div className="flex-1">
              <div className="font-medium">{i.name}</div>
              <div className="text-sm text-secondary">${i.price.toFixed(2)}</div>
            </div>
            <div className="flex items-center gap-3">
              <input 
                type="number" 
                min={1} 
                value={i.qty} 
                onChange={e => setQty(i.id, Math.max(1, Number(e.target.value)))} 
                className="w-16 neumorphic-inset p-2 text-center rounded-lg" 
              />
              <button 
                onClick={() => remove(i.id)} 
                className="p-2 neumorphic-flat hover:neumorphic-pressed transition-all rounded-lg"
              >
                <TrashIcon className="size-4 text-secondary" />
              </button>
            </div>
          </div>
        ))}
        {items.length === 0 && (
          <div className="neumorphic-flat p-6 text-center text-secondary">
            Cart is empty
          </div>
        )}
      </div>
      <div className="neumorphic-flat p-4 space-y-3">
        <div className="flex justify-between">
          <span className="text-secondary">Subtotal</span>
          <span className="font-medium">${subtotal.toFixed(2)}</span>
        </div>
        <div className="flex justify-between">
          <span className="text-secondary">Tax 12%</span>
          <span className="font-medium">${tax.toFixed(2)}</span>
        </div>
        <div className="flex justify-between items-center gap-2">
          <span className="text-secondary">Discount</span>
          <input 
            type="number" 
            min={0} 
            value={discount} 
            onChange={e => setDiscount(Math.max(0, Number(e.target.value)))} 
            className="w-24 neumorphic-inset p-2 text-right rounded-lg" 
          />
        </div>
        <div className="flex justify-between font-semibold text-xl text-primary">
          <span>Total</span>
          <span>${total.toFixed(2)}</span>
        </div>
      </div>
      <CheckoutModal total={total} />
    </div>
  )
}